css:
/* 感谢食用小狗爱的美化，接下来请阅读一下食用须知！！
    插图和引言都可以自定义的，插图使用猫箱外链导入图片后找到有小狗爪🐾🐾的代码就可以自行更换啦！ 
    猫箱链接：https://catbox.moe/ 
*/

/* --- 字体导入 (保持不变) --- */
@import url("https://fontsapi.zeoseven.com/256/main/result.css"); /* 汇文明朝体 */
@import url("https://fontsapi.zeoseven.com/237/main/result.css"); /* 香萃打字机体 */

body, 
#chat, 
.text_pole, 
textarea, 
select, 
.menu_button, 
h3, 
h4,
code,
.mes .mes_text {
    font-family: 'Huiwen-mincho', "汇文明朝体", sans-serif !important; 
}
.mes .ch_name .name_text,
#ch_name1,
#character_name_pole {
    font-family: 'XiangcuiDazijitiW15', "香萃打字机体", monospace !important;
}

:root {
    --ls-bg: #FFFDF5;                 /* 主背景：奶油白 */
    --ls-card-bg: rgba(255, 253, 245, 0.95); /* 卡片背景：半透明奶油白 */
    --ls-primary: #FDEEAA;            /* 主色调：柠檬黄 */
    --ls-secondary: #FFF5D6;          /* 辅助色：奶泡黄 */
    --ls-text-primary: #795548;        /* 主文本：可可棕 */
    --ls-text-secondary: #A1887F;      /* 次文本：奶茶棕 */
    --ls-glow: rgba(253, 238, 170, 0.5); /* 辉光：柔和的柠檬光晕 */
    --ls-highlight: rgba(255, 253, 245, 0.8); /* 纯净高光 */
    --ls-shadow-light: #FFFFFF;       /* 新拟态亮部阴影 */
    --ls-shadow-dark: #E9E4D4;        /* 新拟态暗部阴影 */
    --white50a:  #816d66;
}


.mes {
    padding: 0;
    margin-bottom: 30px;
    width: 100%;
}

.mes .mes_block {
    position: relative;
    width: 100%;
    min-height: auto;
    margin-left: 0;
    padding: 20px;
    background-color: var(--ls-card-bg) !important; 
    backdrop-filter: blur(10px);
    -webkit-backdrop-filter: blur(10px);
    border-radius: 16px;
    box-shadow: 
        0 4px 20px rgba(240, 220, 150, 0.15), 
        0 0 0 1px rgba(255, 255, 255, 0.8);
    border: 1px solid rgba(255, 255, 255, 0.7);
    margin-bottom: 30px;
}

.mes .avatar {
    display: block; position: absolute; z-index: 10;
    top: 20px; left: 30px; width: 120px; height: 160px;
    border: none; border-radius: 8px; overflow: hidden;
    padding: 0; background: none;
    box-shadow: 
        inset 0 0 1px 1px rgba(255, 255, 255, 0.7),
        0px 4px 12px rgba(240, 220, 150, 0.3);
}
.mes .avatar img { width: 100%; height: 100%; object-fit: cover; border-radius: 8px; }

.mes .avatar::after {
    content: "VOLUME Ⅰ";
    position: absolute; bottom: 0; left: 0;
    width: 100%; height: 30px;
    background-color: var(--ls-secondary); 
    display: flex; align-items: center; justify-content: center;
    color: var(--ls-text-secondary); 
    font-family: "Georgia", "Times New Roman", serif;
    font-size: 11px; font-weight: 600; letter-spacing: 2px; text-transform: uppercase;
    text-shadow: 1px 1px 1px rgba(255, 255, 255, 0.7);
}
.mes[is_user="true"] .avatar::after {
    content: "Bookmark";
    background-color: var(--ls-primary); 
    color: var(--ls-text-primary); 
}

.mes .avatar img { position: relative; z-index: 1; }
.mes .avatar::after { z-index: 10; }

/* 信息 */
.mes .ch_name { position: relative; z-index: 2; padding: 0 0 20px 160px; min-height: 160px; display: block; }
.mes .ch_name .name_text {
    font-size: 1.3em; font-weight: 600;
    color: var(--ls-text-primary); 
}


/*  🐾🐾这里是信息区域！可以自改 \A是换行符 🐾🐾 */
.mes .ch_name .name_text::before { content: '本次阅读：《'; font-weight: normal; color: var(--ls-text-secondary); }
.mes .ch_name .name_text::after { content: ' 》'; font-weight: normal; color: var(--ls-text-secondary); }
.mes .ch_name::after {
    content: '现代/爱情/文艺/2025-10-23 (东京)\A最佳主角x并非小狗\A章节：未完待续\A……汪！૮ >⸝⸝⸝⸝< ა';
    white-space: pre; display: block; margin-top: 10px;
    font-size: 13px; line-height: 1.8;
    color: var(--ls-text-secondary); 
    letter-spacing: 1px;
}

/* 引言 */
.mes .mes_text {
    position: relative; padding-top: 250px; margin: 0; 
    padding-left: 20px; border: none;
    border-left: 2px solid var(--ls-secondary); 
    text-align: left; font-size: 14px; line-height: 2; letter-spacing: 1px;
    color: var(--ls-text-primary); 
}

/*  🐾🐾这里是char的引言部分！可以自改 \A是换行符 🐾🐾 */
.mes .mes_text::before {
    content: "\A Then we kissed, like two mirrors of pain,\A peeling off little by little the silver filaments of bitterness from each other's bones. ";
    position: absolute; top: 0; left: 20px; 
    width: calc(100% - 20px);
    display: block; white-space: pre-wrap;
    font-family: "Georgia", "Times New Roman", serif;
    font-style: italic; font-size: 1em; line-height: 1.6;
    color: #F0C987; 
}


/*  🐾🐾这里是user的引言部分！可以自改 \A是换行符 🐾🐾 */
.mes[is_user="true"] .mes_text::before {
    content: "I do not ask thee into the house.\A Come into my infinite loneliness, my Lover.";
}

/*  🐾🐾这里是char的图片部分！可以自改  🐾🐾 */
.mes .mes_text::after {
    content: ''; background-image: url('https://files.catbox.moe/zdu2fk.jpg');
    position: absolute; top: 70px; left: 20px;
    width: calc(100% - 20px); height: 150px;
    background-size: cover; background-position: center; border-radius: 8px;
    box-shadow: 0 4px 15px rgba(240, 220, 150, 0.3);
}


/*  🐾🐾这里是user的图片部分！可以自改  🐾🐾 */
.mes[is_user="true"] .mes_text::after { background-image: url('https://files.catbox.moe/zdu2fk.jpg'); }


/* 排版 */
.mes .mes_text { counter-reset: hidden-counter visible-counter; }
.mes .mes_text p { text-indent: 2em; padding-left: 0; margin-top: 0; margin-bottom: 0.5em; }
.mes_text p q, .mes_text p code, .mes_text p i, .mes_text p em { text-indent: 0 !important; padding-left: 0.5em !important; }
.mes .mes_text p::before { counter-increment: hidden-counter; content: ""; display: none; }
.mes .mes_text p:nth-of-type(3n + 1) { margin-top: 2.5em; position: relative; }
.mes .mes_text p:nth-of-type(3n + 1)::before {
    counter-increment: visible-counter; content: counter(visible-counter); 
    position: absolute; top: -1.5em; left: 50%; transform: translateX(-50%);
    display: block; text-align: center; font-size: 1.1em;
    font-weight: 600; color: var(--ls-primary); 
    text-indent: 0;
}
.mes .mes_text p[style*="text-align: center"] {
    text-indent: 0; padding-left: 0; font-style: italic;
    color: var(--ls-text-secondary); 
}

.mes .mes_timer, .mes .mesIDDisplay, .mes .tokenCounterDisplay { display: block !important; position: absolute; z-index: 10; background: none !important; padding: 0 !important; color: inherit; border: none !important; border-radius: 0 !important; box-shadow: none !important; overflow: visible; }
.mes .mes_timer, .mes .mes_timer::before, .mes .mes_timer::after, .mes .mesIDDisplay, .mes .mesIDDisplay::before, .mes .mesIDDisplay::after, .mes .tokenCounterDisplay, .mes .tokenCounterDisplay::after { font-family: 'Huiwen-mincho', "汇文明朝体", sans-serif; font-style: normal; font-size: 13px; font-weight: normal; color: var(--ls-text-secondary); white-space: nowrap; }
.mes:not([is_user="true"]) .mes_timer::before { content: "“限时 "; }
.mes:not([is_user="true"]) .mes_timer::after { content: " 秒猜谜：小小狗走了 "; }
.mes:not([is_user="true"]) .mesIDDisplay::after { content: " 步, 咬了 "; }
.mes:not([is_user="true"]) .tokenCounterDisplay::after { content: " 口。…猜到了吗？”"; }
.mes[is_user="true"] .mes_timer { display: none !important; }
.mes[is_user="true"] .mes_timer::before, .mes[is_user="true"] .mes_timer::after { content: "" !important; }
.mes[is_user="true"] .mesIDDisplay::before { content: "“小小狗走了 "; }
.mes[is_user="true"] .mesIDDisplay::after { content: " 步, 咬了 "; }
.mes[is_user="true"] .tokenCounterDisplay::after { content: " 口。…是剪刀！”"; }
.mes:not([is_user="true"]) .mes_timer { top: 162px; left: 185px; } .mes:not([is_user="true"]) .mesIDDisplay { top: 162px; left:340px; } .mes:not([is_user="true"]) .tokenCounterDisplay { top: 162px; left: 415px; } .mes[is_user="true"] .mesIDDisplay { top: 162px; left: 185px; } .mes[is_user="true"] .tokenCounterDisplay { top: 162px; left: 340px; }


/* --- 文本样式细节 --- */
.mes_text b, .mes_text strong { color: var(--ls-text-primary); font-weight: 700; text-shadow: 0 0 1px rgba(121, 85, 72, 0.1); }
.mes_text i, .mes_text em { display: inline; position: relative; -webkit-box-decoration-break: clone; box-decoration-break: clone; background: none; quotes: none; padding: 0.1em 0.2em 0.3em 0.2em; margin: 0; border-bottom: 1px solid; border-image-source: linear-gradient( to right, #F0C987 0%, rgba(240, 201, 135, 0) 80% ); border-image-slice: 1; color: var(--ls-text-secondary); font-style: italic; vertical-align: initial; }
.mes_text code, .mes_text blockquote { display: inline-block; position: relative; padding: 0.2em 0.6em; margin: 0 0.2em; background: transparent; border: 1px solid rgba(240, 220, 150, 0.3); border-radius: 6px; box-shadow: inset 0 0 2px var(--ls-highlight), 0 1px 2px rgba(240, 220, 150, 0.15); }
.mes_text code { color: #F0C987; font-family: "SF Mono", "Menlo", "Monaco", monospace; font-size: 0.9em; }
.mes_text s, .mes_text del { color: #c4b8b5; text-decoration-color: #c4b8b5; }
.mes_text q {
    display: inline;
    position: relative;
    -webkit-box-decoration-break: clone;
    box-decoration-break: clone;
    background-color: #FFF8E1;     
    color: var(--ls-text-primary);    
    border-radius: 20px;          
    padding: 0.4em 0.9em;        
    padding-bottom: 0.5em;        
    margin: 0 0.2em;
    line-height: 1.8;          
    box-shadow: 
        inset 0 1.5px 2px rgba(255, 255, 255, 0.7),
        inset 0 -1.5px 2px rgba(221, 203, 169, 0.5),
        0 3px 6px rgba(210, 187, 161, 0.3);
    quotes: none; 
    border: none; 
}


.mes_text q::after {
    content: ''; 
    position: absolute; 
    z-index: 5; 
    background-image: url('https://files.catbox.moe/p5mcb1.png');

    background-size: contain;   
    background-repeat: no-repeat;
    width: 30px;  /* 小狗装饰的宽度 */
    height: 30px; /* 小狗装饰的高度 */
    top: -8px;   /* 向上偏移的距离。负值越大，越靠上 */
    left: -7px;   /* 向右偏移的距离。正值越大，越靠右 */
    pointer-events: none; 
}


