input[type="checkbox"],
input[type="radio"] {
    appearance: none;
    -webkit-appearance: none;
    position: relative;
    cursor: pointer;
    vertical-align: middle;
    margin-right: 8px;
    width: 1.3em;
    height: 1.3em;
    background-color: var(--ls-bg); 
    border: none; 
    box-shadow: 
        0 2px 4px rgba(240, 220, 150, 0.4),
        inset 0 0 1px 1px rgba(161, 136, 127, 0.15),
        inset 0 2px 3px -1px rgba(255, 255, 255, 1),
        inset 0 -2px 3px -1px rgba(121, 85, 72, 0.1);

    transition: all 0.15s cubic-bezier(0.68, -0.55, 0.27, 1.55); 
}

input[type="checkbox"] {
    border-radius: 8px;
}
input[type="radio"] {
    border-radius: 50%;
}

input[type="checkbox"]:checked,
input[type="radio"]:checked {
    background-color: var(--ls-primary); 

    box-shadow: 
        0 3px 6px var(--ls-glow),
        inset 0 0 1px 1px rgba(161, 136, 127, 0.1),
        inset 0 1px 1px rgba(255, 255, 255, 0.8),
        inset 0 -1px 1px rgba(121, 85, 72, 0.1);
}

input[type="checkbox"]:checked::after {
    content: '✔';
    color: var(--ls-text-primary);
    font-size: 0.9em;
    font-weight: 900;
    text-shadow: 0 1px 0 rgba(255, 255, 255, 0.3);
    position: absolute;
    top: 51%; left: 50%;
    transform: translate(-50%, -50%);
    line-height: 1;
}

input[type="radio"]:checked::after {
    content: '';
    width: 0.5em; 
    height: 0.5em;
    border-radius: 50%;
    background-color: var(--ls-text-primary);
    position: absolute;
    top: 50%; left: 50%;
    transform: translate(-50%, -50%);
}


input[type="checkbox"]:hover,
input[type="radio"]:hover {
    transform: scale(1.1); 
}

input[type="checkbox"]:active,
input[type="radio"]:active {
    transform: scale(0.95); 
    transition-duration: 0.1s;
    box-shadow: inset 0 2px 4px rgba(121, 85, 72, 0.2);
}

input[type="range"] {
-webkit-appearance: none;
appearance: none;
width: 100%;
background: transparent;
cursor: pointer;
outline: none;
padding: 0; 
box-shadow: none !important;
filter: none !important;
}

/* --- 滑块拇指 (Thumb) 样式 --- */
/* A. Webkit浏览器 */
input[type="range"]::-webkit-slider-thumb {
    -webkit-appearance: none;

    height: 50px;
    width: 50px;
    /* 修正这里的 margin-top 值 */
    margin-top: -20px; 

    background-image: url('https://files.catbox.moe/ysdq4u.png');
    background-size: contain;
    background-repeat: no-repeat;
    background-position: center;
    background-color: transparent;
    border: none;

    transition: transform 0.2s ease-out;
}

/* B. Firefox浏览器 */
input[type="range"]::-moz-range-thumb {
    height: 50px;
    width: 50px;

    background-image: url('https://files.catbox.moe/ysdq4u.png');
    background-size: contain;
    background-repeat: no-repeat;
    background-position: center;
    background-color: transparent;
    border: none;
    border-radius: 0; /* Firefox可能需要重置圆角 */

    transition: transform 0.2s ease-out;
}

/* --- 交互效果 --- */
input[type="range"]:hover::-webkit-slider-thumb {
    transform: scale(1.15); /* 悬停时放大，提供反馈 */
}
input[type="range"]:hover::-moz-range-thumb {
    transform: scale(1.15);
}

input[type="range"]:active::-webkit-slider-thumb {
    transform: scale(1.1); /* 点击拖动时稍微缩小一点，模拟按压感 */
}
input[type="range"]:active::-moz-range-thumb {
    transform: scale(1.1);
}

